/// <reference types="bun-types" />

declare module '*.css' {
  const content: string;
  export default content;
}

declare module '*.gif' {
  const src: string;
  export default src;
}

declare module '*.png' {
  const src: string;
  export default src;
}

declare module '*.svg' {
  const src: string;
  export default src;
}
